import { HttpException, HttpStatus } from '@nestjs/common';
import {
  ErrorType,
  ErrorCode,
  ErrorContext,
  ErrorMetadata,
  ErrorDetail,
} from './error.types';

export class AppError extends HttpException {
  public readonly errorType: ErrorType;
  public readonly errorCode: ErrorCode;
  public readonly context?: ErrorContext;
  public readonly details?: ErrorDetail[];
  public readonly timestamp: string;
  public readonly requestId?: string;
  public readonly traceId?: string;

  constructor(
    message: string,
    statusCode: HttpStatus,
    errorType: ErrorType,
    errorCode: ErrorCode,
    options?: {
      context?: ErrorContext;
      details?: ErrorDetail[];
      requestId?: string;
      traceId?: string;
      cause?: Error;
    },
  ) {
    super(message, statusCode);

    this.errorType = errorType;
    this.errorCode = errorCode;
    this.context = options?.context;
    this.details = options?.details;
    this.requestId = options?.requestId;
    this.traceId = options?.traceId;
    this.timestamp = new Date().toISOString();

    if (options?.cause) {
      this.cause = options.cause;
    }
  }

  public getMetadata(): ErrorMetadata {
    return {
      timestamp: this.timestamp,
      requestId: this.requestId,
      traceId: this.traceId,
      statusCode: this.getStatus(),
      errorType: this.errorType,
      errorCode: this.errorCode,
      context: this.context,
      details: this.details,
      stack: this.stack,
    };
  }

  public toJSON(): ErrorMetadata {
    return this.getMetadata();
  }

  // Static factory methods for common error types
  static validationFailed(
    message: string = 'Validation failed',
    details?: ErrorDetail[],
    context?: ErrorContext,
  ): AppError {
    return new AppError(
      message,
      HttpStatus.BAD_REQUEST,
      ErrorType.VALIDATION,
      ErrorCode.VALIDATION_FAILED,
      { context, details },
    );
  }

  static invalidInput(
    message: string = 'Invalid input provided',
    field?: string,
    value?: any,
    context?: ErrorContext,
  ): AppError {
    const details = field ? [{ field, message, value }] : undefined;
    return new AppError(
      message,
      HttpStatus.BAD_REQUEST,
      ErrorType.VALIDATION,
      ErrorCode.INVALID_INPUT,
      { context, details },
    );
  }

  static unauthorized(
    message: string = 'Unauthorized access',
    context?: ErrorContext,
  ): AppError {
    return new AppError(
      message,
      HttpStatus.UNAUTHORIZED,
      ErrorType.AUTHENTICATION,
      ErrorCode.INVALID_CREDENTIALS,
      { context },
    );
  }

  static forbidden(
    message: string = 'Access forbidden',
    context?: ErrorContext,
  ): AppError {
    return new AppError(
      message,
      HttpStatus.FORBIDDEN,
      ErrorType.AUTHORIZATION,
      ErrorCode.INSUFFICIENT_PERMISSIONS,
      { context },
    );
  }

  static notFound(
    resource: string,
    identifier?: string,
    context?: ErrorContext,
  ): AppError {
    const message = identifier
      ? `${resource} with identifier '${identifier}' not found`
      : `${resource} not found`;

    return new AppError(
      message,
      HttpStatus.NOT_FOUND,
      ErrorType.NOT_FOUND,
      ErrorCode.RESOURCE_NOT_FOUND,
      {
        context: {
          ...context,
          resource,
          identifier,
        },
      },
    );
  }

  static conflict(
    message: string = 'Resource conflict',
    details?: ErrorDetail[],
    context?: ErrorContext,
  ): AppError {
    return new AppError(
      message,
      HttpStatus.CONFLICT,
      ErrorType.CONFLICT,
      ErrorCode.RESOURCE_CONFLICT,
      { context, details },
    );
  }

  static duplicateResource(
    resource: string,
    field: string,
    value: any,
    context?: ErrorContext,
  ): AppError {
    const message = `${resource} with ${field} '${value}' already exists`;

    return new AppError(
      message,
      HttpStatus.CONFLICT,
      ErrorType.CONFLICT,
      ErrorCode.DUPLICATE_RESOURCE,
      {
        context: {
          ...context,
          resource,
          field,
          value,
        },
        details: [{ field, message, value }],
      },
    );
  }

  static internalError(
    message: string = 'Internal server error',
    cause?: Error,
    context?: ErrorContext,
  ): AppError {
    return new AppError(
      message,
      HttpStatus.INTERNAL_SERVER_ERROR,
      ErrorType.INTERNAL_SERVER,
      ErrorCode.INTERNAL_ERROR,
      { context, cause },
    );
  }

  static serviceUnavailable(service: string, context?: ErrorContext): AppError {
    const message = `${service} service is currently unavailable`;

    return new AppError(
      message,
      HttpStatus.SERVICE_UNAVAILABLE,
      ErrorType.SERVICE_UNAVAILABLE,
      ErrorCode.EXTERNAL_SERVICE_ERROR,
      {
        context: {
          ...context,
          service,
        },
      },
    );
  }

  static rateLimitExceeded(
    limit?: number,
    windowMs?: number,
    context?: ErrorContext,
  ): AppError {
    const message = limit
      ? `Rate limit exceeded. Maximum ${limit} requests per ${windowMs}ms allowed`
      : 'Rate limit exceeded';

    return new AppError(
      message,
      HttpStatus.TOO_MANY_REQUESTS,
      ErrorType.RATE_LIMIT,
      ErrorCode.RATE_LIMIT_EXCEEDED,
      {
        context: {
          ...context,
          limit,
          windowMs,
        },
      },
    );
  }

  static databaseError(
    message: string = 'Database operation failed',
    cause?: Error,
    context?: ErrorContext,
  ): AppError {
    return new AppError(
      message,
      HttpStatus.INTERNAL_SERVER_ERROR,
      ErrorType.DATABASE,
      ErrorCode.DATABASE_CONNECTION_FAILED,
      { context, cause },
    );
  }

  static timeout(
    operation: string,
    timeoutMs: number,
    context?: ErrorContext,
  ): AppError {
    const message = `${operation} operation timed out after ${timeoutMs}ms`;

    return new AppError(
      message,
      HttpStatus.REQUEST_TIMEOUT,
      ErrorType.TIMEOUT,
      ErrorCode.TIMEOUT,
      {
        context: {
          ...context,
          operation,
          timeoutMs,
        },
      },
    );
  }
}

export enum ErrorType {
  VALIDATION = 'VALIDATION',
  AUTHENTICATION = 'AUTHENTICATION',
  AUTHORIZATION = 'AUTHORIZATION',
  NOT_FOUND = 'NOT_FOUND',
  CONFLICT = 'CONFLICT',
  INTERNAL_SERVER = 'INTERNAL_SERVER',
  BAD_REQUEST = 'BAD_REQUEST',
  SERVICE_UNAVAILABLE = 'SERVICE_UNAVAILABLE',
  RATE_LIMIT = 'RATE_LIMIT',
  DATABASE = 'DATABASE',
  NETWORK = 'NETWORK',
  TIMEOUT = 'TIMEOUT',
  BUSINESS = 'BUSINESS',
  UNKNOWN = 'UNKNOWN',
}

export enum ErrorCode {
  // Validation Errors
  VALIDATION_FAILED = 'VALIDATION_FAILED',
  INVALID_INPUT = 'INVALID_INPUT',
  MISSING_REQUIRED_FIELD = 'MISSING_REQUIRED_FIELD',

  // Authentication Errors
  INVALID_CREDENTIALS = 'INVALID_CREDENTIALS',
  TOKEN_EXPIRED = 'TOKEN_EXPIRED',
  TOKEN_INVALID = 'TOKEN_INVALID',
  INSUFFICIENT_PERMISSIONS = 'INSUFFICIENT_PERMISSIONS',

  // Resource Errors
  RESOURCE_NOT_FOUND = 'RESOURCE_NOT_FOUND',
  USER_NOT_FOUND = 'USER_NOT_FOUND',
  PRODUCT_NOT_FOUND = 'PRODUCT_NOT_FOUND',

  // Conflict Errors
  RESOURCE_CONFLICT = 'RESOURCE_CONFLICT',
  DUPLICATE_RESOURCE = 'DUPLICATE_RESOURCE',
  EMAIL_ALREADY_EXISTS = 'EMAIL_ALREADY_EXISTS',

  // System Errors
  DATABASE_CONNECTION_FAILED = 'DATABASE_CONNECTION_FAILED',
  EXTERNAL_SERVICE_ERROR = 'EXTERNAL_SERVICE_ERROR',
  RATE_LIMIT_EXCEEDED = 'RATE_LIMIT_EXCEEDED',
  TIMEOUT = 'TIMEOUT',

  // Business Logic Errors
  INSUFFICIENT_BALANCE = 'INSUFFICIENT_BALANCE',
  INVALID_OPERATION = 'INVALID_OPERATION',
  RESOURCE_LOCKED = 'RESOURCE_LOCKED',

  // Generic Errors
  INTERNAL_ERROR = 'INTERNAL_ERROR',
  UNKNOWN_ERROR = 'UNKNOWN_ERROR',
}

export interface ErrorContext {
  requestId?: string;
  traceId?: string;
  userId?: string;
  resource?: string;
  action?: string;
  timestamp?: string;
  [key: string]: any;
}

export interface ErrorDetail {
  field?: string;
  message?: string;
  code?: string;
  value?: any;
}

export interface ErrorMetadata {
  timestamp: string;
  requestId?: string;
  traceId?: string;
  path?: string;
  method?: string;
  statusCode: number;
  errorType: ErrorType;
  errorCode: ErrorCode;
  message?: string;
  context?: ErrorContext;
  details?: ErrorDetail[];
  stack?: string;
}

import {
  ExceptionFilter,
  Catch,
  ArgumentsHost,
  HttpException,
  Logger,
} from '@nestjs/common';
import { FastifyRequest, FastifyReply } from 'fastify';
import { ConfigService } from '@nestjs/config';
import { AppError } from '@/common/errors/app.error';
import { ApplicationError } from '@/common/domain/errors/application.error';
import {
  createErrorResponse,
  createValidationErrorResponse,
} from '@/common/interfaces/error-response.interface';

/**
 * 🔍 Global Exception Filter
 *
 * Centralized error handling with:
 * - Structured error responses
 * - Request ID correlation
 * - Production safety (no stack traces in prod)
 * - Security error redaction
 */
@Catch()
export class GlobalExceptionFilter implements ExceptionFilter {
  private readonly logger = new Logger(GlobalExceptionFilter.name);

  constructor(private readonly configService: ConfigService) {}

  catch(exception: unknown, host: ArgumentsHost): void {
    const ctx = host.switchToHttp();
    const response = ctx.getResponse<FastifyReply>(); // FastifyReply
    const request = ctx.getRequest<FastifyRequest>(); // FastifyRequest

    const errorResponse = this.getErrorResponse(exception, request);

    // Log the error with correlation
    this.logError(exception, request, errorResponse);

    // Fastify uses .code() instead of .status()
    response.code(errorResponse.meta.statusCode).send(errorResponse);
  }

  private getErrorResponse(exception: unknown, request: FastifyRequest) {
    const requestId = request.headers['x-request-id'] as string | undefined;
    const traceId = request.headers['x-trace-id'] as string | undefined;

    // Priority: ApplicationError > AppError > HttpException > Unknown
    if (exception instanceof ApplicationError) {
      return {
        success: false,
        error: {
          code: exception.code,
          type: 'APPLICATION',
          message: exception.message,
          context: exception.context,
        },
        meta: {
          timestamp: new Date().toISOString(),
          requestId,
          traceId,
          path: request.url,
          method: request.method,
          statusCode: exception.statusCode,
        },
      };
    }

    // Handle AppError instances
    if (exception instanceof AppError) {
      const metadata = exception.getMetadata();

      // Add request context
      metadata.requestId = requestId;
      metadata.traceId = traceId;
      metadata.path = request.url;
      metadata.method = request.method;

      // Handle validation errors specially
      if (exception.errorType === 'VALIDATION' && exception.details) {
        return createValidationErrorResponse(
          metadata,
          exception.details as Array<{
            field: string;
            message: string;
            value?: any;
          }>,
        );
      }

      return createErrorResponse(metadata);
    }

    // Handle HttpException (including ValidationPipe errors)
    if (exception instanceof HttpException) {
      const status = exception.getStatus();
      const response = exception.getResponse();

      // Handle ValidationPipe errors
      if (this.isValidationError(response)) {
        const validationErrors = this.extractValidationErrors(response);

        return {
          success: false,
          error: {
            code: 'VALIDATION_FAILED',
            type: 'VALIDATION',
            message: 'Validation failed',
            details: validationErrors,
          },
          meta: {
            timestamp: new Date().toISOString(),
            requestId,
            traceId,
            path: request.url,
            method: request.method,
            statusCode: status,
          },
        };
      }

      // Handle other HTTP exceptions
      const message = this.extractErrorMessage(response);

      return {
        success: false,
        error: {
          code: this.getErrorCodeFromStatus(status),
          type: this.getErrorTypeFromStatus(status),
          message,
        },
        meta: {
          timestamp: new Date().toISOString(),
          requestId,
          traceId,
          path: request.url,
          method: request.method,
          statusCode: status,
        },
      };
    }

    // Handle unexpected errors
    return this.createUnknownErrorResponse(exception, request);
  }

  private isValidationError(response: any): boolean {
    return (
      response &&
      typeof response === 'object' &&
      'message' in response &&
      Array.isArray(response.message)
    );
  }

  private extractValidationErrors(
    response: any,
  ): Array<{ field: string; message: string; value?: any }> {
    if (!response.message || !Array.isArray(response.message)) {
      return [];
    }

    return response.message.map((error: any) => {
      if (typeof error === 'string') {
        return { message: error };
      }

      if (typeof error === 'object' && error !== null) {
        return {
          field: error.property,
          message: Object.values(error.constraints || {}).join(', '),
          value: error.value,
        };
      }

      return { message: String(error) };
    });
  }

  private extractErrorMessage(response: any): string {
    if (typeof response === 'string') {
      return response;
    }

    if (typeof response === 'object' && response !== null) {
      const message = response.message;

      if (Array.isArray(message)) {
        return message.join(', ');
      }

      if (typeof message === 'string') {
        return message;
      }

      // Extract first message from nested object
      if (typeof message === 'object') {
        const firstKey = Object.keys(message)[0];
        const firstMessage = message[firstKey];
        if (Array.isArray(firstMessage)) {
          return firstMessage.join(', ');
        }
        if (typeof firstMessage === 'string') {
          return firstMessage;
        }
      }
    }

    return 'Internal server error';
  }

  private getErrorCodeFromStatus(status: number): string {
    const statusCodes: Record<number, string> = {
      400: 'BAD_REQUEST',
      401: 'UNAUTHORIZED',
      403: 'FORBIDDEN',
      404: 'NOT_FOUND',
      409: 'CONFLICT',
      429: 'TOO_MANY_REQUESTS',
      500: 'INTERNAL_SERVER_ERROR',
      502: 'BAD_GATEWAY',
      503: 'SERVICE_UNAVAILABLE',
    };

    return statusCodes[status] || 'UNKNOWN_ERROR';
  }

  private getErrorTypeFromStatus(status: number): string {
    if (status >= 400 && status < 500) {
      return 'CLIENT_ERROR';
    }

    if (status >= 500) {
      return 'SERVER_ERROR';
    }

    return 'UNKNOWN';
  }

  private createUnknownErrorResponse(
    exception: unknown,
    request: FastifyRequest,
  ) {
    const requestId = request.headers['x-request-id'] as string | undefined;
    const traceId = request.headers['x-trace-id'] as string | undefined;
    const isProduction = this.configService.get('app.nodeEnv') === 'production';

    const baseResponse = {
      success: false,
      error: {
        code: 'INTERNAL_ERROR',
        type: 'INTERNAL_SERVER',
        message: isProduction
          ? 'Internal server error'
          : exception instanceof Error
            ? exception.message
            : 'Unknown error',
      },
      meta: {
        timestamp: new Date().toISOString(),
        requestId,
        traceId,
        path: request.url,
        method: request.method,
        statusCode: 500,
      },
    };

    // Add stack trace in development
    if (!isProduction && exception instanceof Error) {
      return {
        ...baseResponse,
        error: {
          ...baseResponse.error,
          details: [
            {
              field: 'stack',
              message: exception.stack || 'No stack trace available',
            },
          ],
        },
      };
    }

    return baseResponse;
  }

  private logError(
    exception: unknown,
    request: FastifyRequest,
    errorResponse: any,
  ): void {
    const isProduction = this.configService.get('app.nodeEnv') === 'production';
    const requestId = errorResponse.meta.requestId;
    const traceId = errorResponse.meta.traceId;

    const logContext = {
      requestId,
      traceId,
      method: request.method,
      url: request.url,
      userAgent: request.headers['user-agent'],
      ip: request.ip,
      statusCode: errorResponse.meta.statusCode,
      errorType: errorResponse.error.type,
      errorCode: errorResponse.error.code,
    };

    if (exception instanceof HttpException) {
      // Log HTTP exceptions with appropriate level
      const status = exception.getStatus();
      if (status >= 500) {
        this.logger.error('HTTP Server Error', logContext);
      } else if (status >= 400) {
        this.logger.warn('HTTP Client Error', logContext);
      }
    } else {
      // Log unexpected errors
      this.logger.error(
        'Unexpected Error',
        isProduction ? logContext : { ...logContext, exception },
      );
    }
  }
}

import {
  CanActivate,
  ExecutionContext,
  Injectable,
  UnauthorizedException,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { JwtService } from '@nestjs/jwt';
import { ConfigService } from '@nestjs/config';
import { Request } from 'express';
import { Inject } from '@nestjs/common';
import { IS_PUBLIC_KEY } from '../decorators/public.decorator';
import { IS_OPTIONAL_KEY } from '../decorators/optional.decorator';
import { INJECTION_TOKENS } from '@/constants/injection-tokens';
import type { ITokenStore } from '@/modules/auth/infrastructure/token-store/redis-token-store';

interface AuthenticatedRequest extends Request {
  user?: any;
}

@Injectable()
export class AuthGuard implements CanActivate {
  constructor(
    private readonly reflector: Reflector,
    private readonly jwtService: JwtService,
    private readonly configService: ConfigService,
    // Add: inject token store to check blacklist
    @Inject(INJECTION_TOKENS.TOKEN_STORE)
    private readonly tokenStore: ITokenStore,
  ) {}

  async canActivate(context: ExecutionContext): Promise<boolean> {
    const isPublic = this.reflector.getAllAndOverride<boolean>(IS_PUBLIC_KEY, [
      context.getHandler(),
      context.getClass(),
    ]);

    if (isPublic) return true;

    const request = this.getRequest(context);
    const token = this.extractTokenFromRequest(request);

    if (!token) {
      const isOptional = this.reflector.getAllAndOverride<boolean>(
        IS_OPTIONAL_KEY,
        [context.getHandler(), context.getClass()],
      );
      if (isOptional) return true;
      throw new UnauthorizedException('MISSING_TOKEN');
    }

    try {
      const payload = await this.jwtService.verifyAsync(token, {
        secret: this.configService.get<string>('auth.jwt.accessToken.secret'),
      });

      if (!payload.sub || !payload.email || !payload.jti) {
        throw new UnauthorizedException('INVALID_TOKEN_PAYLOAD');
      }

      // Add: check if token is blacklisted
      const isBlacklisted = await this.tokenStore.isAccessTokenBlacklisted(
        payload.jti,
      );
      if (isBlacklisted) {
        throw new UnauthorizedException('TOKEN_REVOKED');
      }

      request.user = payload;

      return true;
    } catch (error) {
      if (process.env.NODE_ENV === 'development') {
        console.error('Auth error:', error);
      }

      throw new UnauthorizedException('INVALID_OR_EXPIRED_TOKEN');
    }
  }

  private getRequest(context: ExecutionContext): AuthenticatedRequest {
    return context.switchToHttp().getRequest<AuthenticatedRequest>();
  }

  private extractTokenFromRequest(request: any): string | undefined {
    const authHeader = request.headers?.authorization;
    if (authHeader?.startsWith('Bearer ')) {
      return authHeader.substring(7);
    }

    return undefined;
  }
}

import { Injectable, CanActivate, ExecutionContext } from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { AppLoggerService } from '@/common/services/logger.service';
import { AppError } from '@/common/errors/app.error';

export interface Permission {
  resource: string;
  action: string;
  conditions?: string[];
}

export interface Role {
  name: string;
  permissions: Permission[];
}

export const ROLES = {
  ADMIN: 'ADMIN',
  USER: 'USER',
  MODERATOR: 'MODERATOR',
  SUPER_ADMIN: 'SUPER_ADMIN',
} as const;

export const PERMISSIONS = {
  // User permissions
  USER_READ_OWN: { resource: 'user', action: 'read', conditions: ['own'] },
  USER_UPDATE_OWN: { resource: 'user', action: 'update', conditions: ['own'] },
  USER_DELETE_OWN: { resource: 'user', action: 'delete', conditions: ['own'] },

  // Product permissions
  PRODUCT_READ: { resource: 'product', action: 'read' },
  PRODUCT_CREATE: { resource: 'product', action: 'create' },
  PRODUCT_UPDATE_OWN: {
    resource: 'product',
    action: 'update',
    conditions: ['own'],
  },
  PRODUCT_DELETE_OWN: {
    resource: 'product',
    action: 'delete',
    conditions: ['own'],
  },

  // Admin permissions
  USER_READ_ALL: { resource: 'user', action: 'read' },
  USER_UPDATE_ALL: { resource: 'user', action: 'update' },
  USER_DELETE_ALL: { resource: 'user', action: 'delete' },
  PRODUCT_UPDATE_ALL: { resource: 'product', action: 'update' },
  PRODUCT_DELETE_ALL: { resource: 'product', action: 'delete' },
} as const;

export const ROLE_PERMISSIONS: Record<string, Permission[]> = {
  [ROLES.USER]: [
    PERMISSIONS.USER_READ_OWN,
    PERMISSIONS.USER_UPDATE_OWN,
    PERMISSIONS.USER_DELETE_OWN,
    PERMISSIONS.PRODUCT_READ,
    PERMISSIONS.PRODUCT_CREATE,
    PERMISSIONS.PRODUCT_UPDATE_OWN,
    PERMISSIONS.PRODUCT_DELETE_OWN,
  ],
  [ROLES.MODERATOR]: [
    ...ROLE_PERMISSIONS[ROLES.USER],
    PERMISSIONS.PRODUCT_UPDATE_ALL,
  ],
  [ROLES.ADMIN]: [
    ...ROLE_PERMISSIONS[ROLES.MODERATOR],
    PERMISSIONS.USER_READ_ALL,
    PERMISSIONS.USER_UPDATE_ALL,
    PERMISSIONS.PRODUCT_DELETE_ALL,
  ],
  [ROLES.SUPER_ADMIN]: [
    // Super admin has all permissions
  ],
};

@Injectable()
export class AuthorizationGuard implements CanActivate {
  constructor(
    private readonly reflector: Reflector,
    private readonly logger: AppLoggerService,
  ) {}

  canActivate(context: ExecutionContext): boolean {
    const request = context.switchToHttp().getRequest();
    const user = request.user;

    // Check if user is authenticated
    if (!user) {
      this.logger.security('Unauthorized access attempt - no user found', {
        path: request.path,
        method: request.method,
        ip: request.ip,
        userAgent: request.headers['user-agent'],
      });

      throw AppError.unauthorized('Authentication required');
    }

    // Get required permissions from metadata
    const requiredPermissions = this.reflector.get<string[]>('permissions', []);
    const requiredRoles = this.reflector.get<string[]>('roles', []);

    try {
      // Check if user has required roles
      if (
        requiredRoles.length > 0 &&
        !this.hasRequiredRoles(user.role, requiredRoles)
      ) {
        this.logger.security('Access denied - insufficient role', {
          userId: user.id,
          userRole: user.role,
          requiredRoles,
          path: request.path,
          method: request.method,
          ip: request.ip,
        });

        throw AppError.forbidden('Insufficient permissions');
      }

      // Check if user has required permissions
      if (
        requiredPermissions.length > 0 &&
        !this.hasRequiredPermissions(user, requiredPermissions, request)
      ) {
        this.logger.security('Access denied - insufficient permissions', {
          userId: user.id,
          userRole: user.role,
          requiredPermissions,
          path: request.path,
          method: request.method,
          ip: request.ip,
        });

        throw AppError.forbidden('Insufficient permissions');
      }

      // Log successful authorization
      this.logger.auth('Access granted', {
        userId: user.id,
        userRole: user.role,
        requiredRoles,
        requiredPermissions,
        path: request.path,
        method: request.method,
      });

      return true;
    } catch (error) {
      this.logger.errorWithException(
        'Authorization guard error',
        error as Error,
        undefined,
        {
          userId: user.id,
          path: request.path,
          method: request.method,
        },
      );

      throw AppError.forbidden('Authorization failed');
    }
  }

  private hasRequiredRoles(userRole: string, requiredRoles: string[]): boolean {
    return requiredRoles.includes(userRole);
  }

  private hasRequiredPermissions(
    user: any,
    requiredPermissions: string[],
    request: any,
  ): boolean {
    const userPermissions = ROLE_PERMISSIONS[user.role] || [];

    return requiredPermissions.every((requiredPermission) => {
      const permission = this.parsePermission(requiredPermission);
      return this.checkPermission(user, permission, request);
    });
  }

  private parsePermission(permissionString: string): Permission {
    const [resource, action] = permissionString.split(':');
    return { resource, action };
  }

  private checkPermission(
    user: any,
    permission: Permission,
    request: any,
  ): boolean {
    const userPermissions = ROLE_PERMISSIONS[user.role] || [];

    const hasPermission = userPermissions.some(
      (userPermission) =>
        userPermission.resource === permission.resource &&
        userPermission.action === permission.action,
    );

    if (!hasPermission) {
      return false;
    }

    // Check conditions if specified
    if (permission.conditions && permission.conditions.length > 0) {
      return this.checkConditions(user, permission, request);
    }

    return true;
  }

  private checkConditions(
    user: any,
    permission: Permission,
    request: any,
  ): boolean {
    return permission.conditions.every((condition) => {
      switch (condition) {
        case 'own':
          return this.checkOwnership(user, permission.resource, request);
        default:
          return true; // Unknown condition, allow by default
      }
    });
  }

  private checkOwnership(user: any, resource: string, request: any): boolean {
    // Extract resource ID from request parameters
    const resourceId =
      request.params.id || request.params.userId || request.params.productId;

    if (!resourceId) {
      return false;
    }

    // Check if user owns the resource
    switch (resource) {
      case 'user':
        return user.id === resourceId;
      case 'product':
        return this.checkProductOwnership(user.id, resourceId);
      default:
        return false;
    }
  }

  private async checkProductOwnership(
    userId: string,
    productId: string,
  ): Promise<boolean> {
    // This would typically involve a database call
    // For now, we'll implement a simple check
    // In a real implementation, you would query the database
    return userId && productId; // Placeholder implementation
  }
}

