import {
  Injectable,
  ExecutionContext,
  UnauthorizedException,
} from '@nestjs/common';
import { AuthGuard } from '@nestjs/passport';
import { Reflector } from '@nestjs/core';
import { IS_PUBLIC_KEY } from '../decorators/public.decorator';
import { INJECTION_TOKENS } from '@/constants/injection-tokens';
import { Inject } from '@nestjs/common';
import type { ITokenStore } from '@/modules/auth/infrastructure/token-store/redis-token-store';

@Injectable()
export class JwtAuthGuard extends AuthGuard('jwt') {
  constructor(
    private reflector: Reflector,
    @Inject(INJECTION_TOKENS.TOKEN_STORE)
    private readonly tokenStore: ITokenStore,
  ) {
    super();
  }

  async canActivate(context: ExecutionContext) {
    const isPublic = this.reflector.getAllAndOverride<boolean>(IS_PUBLIC_KEY, [
      context.getHandler(),
      context.getClass(),
    ]);
    if (isPublic) {
      return true;
    }

    // Let the parent AuthGuard handle JWT validation first
    const result = await super.canActivate(context);
    if (!result) {
      return false;
    }

    // Additional blacklist check
    const request = context.switchToHttp().getRequest();
    const user = request.user;

    if (user?.jti) {
      const isBlacklisted = await this.tokenStore.isAccessTokenBlacklisted(
        user.jti,
      );
      if (isBlacklisted) {
        throw new UnauthorizedException('TOKEN_REVOKED');
      }
    }

    return true;
  }
}

import { Injectable, CanActivate, ExecutionContext } from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { ConfigService } from '@nestjs/config';
import { AppLoggerService } from '@/common/services/logger.service';
import { AppError } from '@/common/errors/app.error';

export interface RateLimitOptions {
  windowMs: number;
  max: number;
  message?: string;
  skipSuccessfulRequests?: boolean;
  skipFailedRequests?: boolean;
}

export interface RateLimitInfo {
  totalHits: number;
  remainingHits: number;
  resetTime: Date;
  windowMs: number;
}

export interface RateLimitStore {
  increment: (key: string, options: RateLimitOptions) => Promise<RateLimitInfo>;
  reset: (key: string) => Promise<void>;
  cleanup: () => Promise<void>;
}

@Injectable()
export class RateLimitGuard implements CanActivate {
  private readonly store: RateLimitStore;
  private readonly defaultOptions: RateLimitOptions;

  constructor(
    private readonly reflector: Reflector,
    private readonly configService: ConfigService,
    private readonly logger: AppLoggerService,
  ) {
    this.store = new MemoryRateLimitStore(logger);
    this.defaultOptions = {
      windowMs: 60 * 1000, // 1 minute
      max: 100, // 100 requests per minute
      message: 'Too many requests, please try again later.',
      skipSuccessfulRequests: false,
      skipFailedRequests: false,
    };
  }

  async canActivate(context: ExecutionContext): Promise<boolean> {
    const request = context.switchToHttp().getRequest();
    const response = context.switchToHttp().getResponse();

    try {
      // Get rate limit options from metadata
      const options = this.getRateLimitOptions(context);

      // Generate key for rate limiting
      const key = this.generateKey(request, options);

      // Check rate limit
      const rateLimitInfo = await this.store.increment(key, options);

      // Add rate limit headers
      this.addRateLimitHeaders(response, rateLimitInfo);

      // Check if rate limit exceeded
      if (rateLimitInfo.totalHits > options.max) {
        this.logger.security('Rate limit exceeded', {
          key,
          totalHits: rateLimitInfo.totalHits,
          max: options.max,
          windowMs: options.windowMs,
          path: request.path,
          method: request.method,
          ip: request.ip,
          userAgent: request.headers['user-agent'],
        });

        throw AppError.rateLimitExceeded(options.max, options.windowMs, {
          key,
          totalHits: rateLimitInfo.totalHits,
          remainingHits: rateLimitInfo.remainingHits,
          resetTime: rateLimitInfo.resetTime,
        });
      }

      // Log rate limit info
      this.logger.http(`Rate limit check passed`, {
        key,
        totalHits: rateLimitInfo.totalHits,
        remainingHits: rateLimitInfo.remainingHits,
        path: request.path,
        method: request.method,
      });

      return true;
    } catch (error) {
      this.logger.errorWithException(
        'Rate limit guard error',
        error as Error,
        undefined,
        {
          path: request.path,
          method: request.method,
          ip: request.ip,
        },
      );

      throw error;
    }
  }

  private getRateLimitOptions(context: ExecutionContext): RateLimitOptions {
    const customOptions = this.reflector.get<Partial<RateLimitOptions>>(
      'rateLimit',
      {},
    );

    return {
      ...this.defaultOptions,
      ...customOptions,
    };
  }

  private generateKey(request: any, options: RateLimitOptions): string {
    // Get user ID if authenticated
    const userId = request.user?.id;

    // Get IP address
    const ip =
      request.ip ||
      request.connection?.remoteAddress ||
      request.socket?.remoteAddress;

    // Get endpoint
    const endpoint = request.path;

    // Generate key based on strategy
    if (userId) {
      // Rate limit per user
      return `rate_limit:user:${userId}:${endpoint}`;
    } else if (ip) {
      // Rate limit per IP
      return `rate_limit:ip:${ip}:${endpoint}`;
    } else {
      // Fallback to global rate limit
      return `rate_limit:global:${endpoint}`;
    }
  }

  private addRateLimitHeaders(
    response: any,
    rateLimitInfo: RateLimitInfo,
  ): void {
    response.setHeader('X-RateLimit-Limit', rateLimitInfo.windowMs);
    response.setHeader(
      'X-RateLimit-Remaining',
      Math.max(0, rateLimitInfo.remainingHits),
    );
    response.setHeader(
      'X-RateLimit-Reset',
      rateLimitInfo.resetTime.toISOString(),
    );
  }
}

// Memory-based rate limit store
export class MemoryRateLimitStore implements RateLimitStore {
  private store = new Map<string, RateLimitInfo>();
  private cleanupInterval: NodeJS.Timeout;

  constructor(private readonly logger: AppLoggerService) {
    // Cleanup expired entries every 5 minutes
    this.cleanupInterval = setInterval(
      () => {
        this.cleanup();
      },
      5 * 60 * 1000,
    );
  }

  async increment(
    key: string,
    options: RateLimitOptions,
  ): Promise<RateLimitInfo> {
    const now = Date.now();
    const resetTime = new Date(now + options.windowMs);

    // Get existing entry
    let entry = this.store.get(key);

    if (!entry) {
      // Create new entry
      entry = {
        totalHits: 1,
        remainingHits: options.max - 1,
        resetTime,
        windowMs: options.windowMs,
      };
    } else {
      // Check if window has expired
      if (now > entry.resetTime.getTime()) {
        // Reset entry
        entry = {
          totalHits: 1,
          remainingHits: options.max - 1,
          resetTime,
          windowMs: options.windowMs,
        };
      } else {
        // Increment existing entry
        entry.totalHits++;
        entry.remainingHits = Math.max(0, options.max - entry.totalHits);
      }
    }

    // Update store
    this.store.set(key, entry);

    return entry;
  }

  async reset(key: string): Promise<void> {
    this.store.delete(key);

    this.logger.http(`Rate limit reset for key: ${key}`, {
      key,
    });
  }

  async cleanup(): Promise<void> {
    const now = Date.now();
    let cleanedCount = 0;

    for (const [key, entry] of this.store.entries()) {
      if (now > entry.resetTime.getTime()) {
        this.store.delete(key);
        cleanedCount++;
      }
    }

    if (cleanedCount > 0) {
      this.logger.http(`Rate limit cleanup completed`, {
        cleanedCount,
        remainingEntries: this.store.size,
      });
    }
  }

  async destroy(): Promise<void> {
    if (this.cleanupInterval) {
      clearInterval(this.cleanupInterval);
    }

    this.store.clear();

    this.logger.http('Rate limit store destroyed');
  }
}

// Decorator for setting rate limit options
export const RateLimit =
  (options: Partial<RateLimitOptions>) =>
  (target: any, propertyKey: string, descriptor: PropertyDescriptor) => {
    Reflect.defineMetadata('rateLimit', options, descriptor.value);
    return descriptor;
  };

// Redis-based rate limit store (for production)
export class RedisRateLimitStore implements RateLimitStore {
  constructor(
    private readonly redis: any,
    private readonly logger: AppLoggerService,
  ) {}

  async increment(
    key: string,
    options: RateLimitOptions,
  ): Promise<RateLimitInfo> {
    const now = Date.now();
    const resetTime = now + options.windowMs;

    // Use Redis INCR with expiration
    const pipeline = this.redis.pipeline();
    pipeline.incr(key);
    pipeline.expire(key, Math.ceil(options.windowMs / 1000));

    const results = await pipeline.exec();
    const totalHits = results[0][1] as number;

    return {
      totalHits,
      remainingHits: Math.max(0, options.max - totalHits),
      resetTime: new Date(resetTime),
      windowMs: options.windowMs,
    };
  }

  async reset(key: string): Promise<void> {
    await this.redis.del(key);

    this.logger.http(`Rate limit reset for key: ${key}`, {
      key,
    });
  }

  async cleanup(): Promise<void> {
    // Redis handles expiration automatically
    // No manual cleanup needed
  }
}

import {
  Injectable,
  CanActivate,
  ExecutionContext,
  ForbiddenException,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { ROLES } from './authorization.guard';

@Injectable()
export class RolesGuard implements CanActivate {
  constructor(private readonly reflector: Reflector) {}

  canActivate(context: ExecutionContext): boolean {
    const requiredRoles = this.reflector.get<string[]>(
      'roles',
      context.getHandler(),
    );

    if (!requiredRoles || requiredRoles.length === 0) {
      return true; // No roles required
    }

    const request = context.switchToHttp().getRequest();
    const user = request.user;

    if (!user) {
      throw new ForbiddenException('User not authenticated');
    }

    const userRole = user.role;
    if (!userRole) {
      throw new ForbiddenException('User role not defined');
    }

    // Check if user has any of the required roles
    const hasRequiredRole = requiredRoles.some((role) => {
      if (role === ROLES.ADMIN) {
        return userRole === ROLES.ADMIN;
      }
      if (role === ROLES.USER) {
        return (
          userRole === ROLES.USER ||
          userRole === ROLES.ADMIN ||
          userRole === ROLES.MODERATOR
        );
      }
      if (role === ROLES.MODERATOR) {
        return userRole === ROLES.MODERATOR || userRole === ROLES.ADMIN;
      }
      return userRole === role;
    });

    if (!hasRequiredRole) {
      throw new ForbiddenException(
        `Insufficient permissions. Required roles: ${requiredRoles.join(', ')}`,
      );
    }

    return true;
  }
}

import { Injectable, Inject } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import {
  S3Client,
  PutObjectCommand,
  GetObjectCommand,
  DeleteObjectCommand,
  ListObjectsV2Command,
  HeadObjectCommand,
} from '@aws-sdk/client-s3';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';
import { Readable } from 'stream';
import type {
  StorageProvider,
  StorageUploadOptions,
  StorageUploadResult,
  StorageDownloadResult,
  StorageDeleteResult,
  StorageListResult,
  StorageConfig,
} from '../storage.interface';
import { STORAGE_CONFIG_KEY } from '../storage.interface';

@Injectable()
export class AwsS3Provider implements StorageProvider {
  private readonly s3Client: S3Client;
  private readonly bucket: string;

  constructor(
    @Inject(ConfigService) private readonly configService: ConfigService,
  ) {
    const storageConfig =
      this.configService.get<StorageConfig>(STORAGE_CONFIG_KEY)!;

    this.s3Client = new S3Client({
      region: storageConfig.awsS3!.region,
      credentials: {
        accessKeyId: storageConfig.awsS3!.accessKeyId,
        secretAccessKey: storageConfig.awsS3!.secretAccessKey,
      },
      endpoint: storageConfig.awsS3!.endpoint,
      forcePathStyle: storageConfig.awsS3!.forcePathStyle || false,
    });

    this.bucket = storageConfig.awsS3!.bucket;
  }

  async upload(
    key: string,
    buffer: Buffer | Readable,
    options?: StorageUploadOptions,
  ): Promise<StorageUploadResult> {
    try {
      const command = new PutObjectCommand({
        Bucket: this.bucket,
        Key: key,
        Body: buffer,
        ContentType: options?.contentType,
        Metadata: options?.metadata,
        ACL: options?.isPublic ? 'public-read' : 'private',
        Expires: options?.expiresAt,
      });

      const response = await this.s3Client.send(command);

      return {
        success: true,
        key,
        url: `https://${this.bucket}.s3.${this.configService.get('storage.awsS3.region')}.${this.configService.get('AWS_S3_DOMAIN', 'amazonaws.com')}/${key}`,
        etag: response.ETag,
        providerResponse: {
          ETag: response.ETag,
          RequestId: response.$metadata.requestId,
        },
      };
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Upload failed',
      };
    }
  }

  async download(key: string): Promise<StorageDownloadResult> {
    try {
      const command = new GetObjectCommand({
        Bucket: this.bucket,
        Key: key,
      });

      const response = await this.s3Client.send(command);

      return {
        success: true,
        stream: response.Body as Readable,
        contentType: response.ContentType,
        size: response.ContentLength,
        providerResponse: {
          ETag: response.ETag,
          RequestId: response.$metadata.requestId,
        },
      };
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Download failed',
      };
    }
  }

  async delete(key: string): Promise<StorageDeleteResult> {
    try {
      const command = new DeleteObjectCommand({
        Bucket: this.bucket,
        Key: key,
      });

      const response = await this.s3Client.send(command);

      return {
        success: true,
        providerResponse: {
          RequestId: response.$metadata.requestId,
        },
      };
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : 'Delete failed',
      };
    }
  }

  async list(prefix?: string, maxKeys?: number): Promise<StorageListResult> {
    try {
      const command = new ListObjectsV2Command({
        Bucket: this.bucket,
        Prefix: prefix,
        MaxKeys: maxKeys,
      });

      const response = await this.s3Client.send(command);

      return {
        success: true,
        files: response.Contents?.map((obj) => ({
          key: obj.Key!,
          size: obj.Size!,
          lastModified: obj.LastModified!,
          etag: obj.ETag,
        })),
        providerResponse: {
          RequestId: response.$metadata.requestId,
        },
      };
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : 'List failed',
      };
    }
  }

  async getSignedUrl(key: string, expiresIn: number): Promise<string> {
    try {
      const command = new GetObjectCommand({
        Bucket: this.bucket,
        Key: key,
      });

      const url = await getSignedUrl(this.s3Client, command, { expiresIn });

      return url;
    } catch (error) {
      throw error;
    }
  }

  async exists(key: string): Promise<boolean> {
    try {
      const command = new HeadObjectCommand({
        Bucket: this.bucket,
        Key: key,
      });

      await this.s3Client.send(command);
      return true;
    } catch {
      return false;
    }
  }

  async getMetadata(key: string): Promise<{
    size: number;
    contentType?: string;
    lastModified: Date;
    etag?: string;
  } | null> {
    try {
      const command = new HeadObjectCommand({
        Bucket: this.bucket,
        Key: key,
      });

      const response = await this.s3Client.send(command);

      return {
        size: response.ContentLength!,
        contentType: response.ContentType,
        lastModified: response.LastModified!,
        etag: response.ETag,
      };
    } catch {
      return null;
    }
  }

  getProviderName(): string {
    return 'AWS S3';
  }

  async validateConfig(): Promise<boolean> {
    try {
      const storageConfig =
        this.configService.get<StorageConfig>(STORAGE_CONFIG_KEY)!;

      if (
        !storageConfig.awsS3?.accessKeyId ||
        !storageConfig.awsS3?.secretAccessKey ||
        !storageConfig.awsS3?.bucket
      ) {
        return false;
      }

      const validationMaxKeys = parseInt(
        this.configService.get('AWS_S3_VALIDATION_MAX_KEYS', '1'),
      );
      await this.s3Client.send(
        new ListObjectsV2Command({
          Bucket: this.bucket,
          MaxKeys: validationMaxKeys,
        }),
      );
      return true;
    } catch {
      return false;
    }
  }
}

import { Module, DynamicModule } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { StorageService } from './storage.service';
import { STORAGE_CONFIG_KEY, StorageConfig } from './storage.interface';
import { AwsS3Provider } from './providers/aws-s3.provider';
import type { StorageProvider } from './storage.interface';

export const STORAGE_PROVIDER = 'StorageProvider';

@Module({})
export class StorageModule {
  static forRoot(): DynamicModule {
    return {
      module: StorageModule,
      providers: [
        {
          provide: STORAGE_PROVIDER,
          inject: [ConfigService],
          useFactory: (config: ConfigService) => {
            const provider = config.get<string>('storage.provider');

            if (!provider) {
              throw new Error(
                '[StorageModule] STORAGE_PROVIDER không été configuré. ' +
                  'Set STORAGE_PROVIDER=aws-s3 trong .env',
              );
            }

            // Never allow local storage in production
            if (
              provider === 'local' &&
              config.get('app.nodeEnv') === 'production'
            ) {
              throw new Error(
                '[StorageModule] Local storage interdit en production. ' +
                  'Utilisez aws-s3, cloudinary, ou google-cloud.',
              );
            }

            switch (provider) {
              case 'aws-s3':
                return new AwsS3Provider(config);
              default:
                throw new Error(
                  `[StorageModule] Provider non supporté: ${provider}`,
                );
            }
          },
        },
        StorageService,
      ],
      exports: [StorageService],
    };
  }
}

import {
  Injectable,
  NestInterceptor,
  ExecutionContext,
  CallHandler,
} from '@nestjs/common';
import { Observable, throwError } from 'rxjs';
import { catchError, tap } from 'rxjs/operators';
import { Request, Response } from 'express';
import {
  AppLoggerService,
  LogMetadata,
} from '@/common/services/logger.service';

@Injectable()
export class LoggingInterceptor implements NestInterceptor {
  constructor(private readonly logger: AppLoggerService) {}

  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
    const startTime = Date.now();
    const request = context.switchToHttp().getRequest<Request>();
    const response = context.switchToHttp().getResponse<Response>();

    const { method, url, ip, headers } = request;
    const requestId = headers['x-request-id'] as string | undefined;
    const traceId = headers['x-trace-id'] as string | undefined;
    const userAgent = headers['user-agent'];

    // Extract user info if available (from auth middleware)
    const user = (request as any).user;
    const userId = user?.id;
    const sessionId = user?.sessionId;

    const metadata: LogMetadata = {
      requestId,
      traceId,
      userId,
      sessionId,
      method,
      url,
      ip,
      userAgent,
    };

    return next.handle().pipe(
      tap(() => {
        // Log successful request
        const endTime = Date.now();
        const duration = endTime - startTime;
        const statusCode = response.statusCode;

        this.logger.logRequest(method, url, statusCode, duration, {
          ...metadata,
          statusCode,
          duration,
          success: statusCode < 400,
        });

        // Log performance for slow requests
        if (duration > 1000) {
          this.logger.performance(
            `${method} ${url}`,
            duration,
            startTime,
            endTime,
            {
              ...metadata,
              type: 'slow_request',
              threshold: 1000,
            },
          );
        }
      }),
      catchError((error) => {
        // Log failed request
        const endTime = Date.now();
        const duration = endTime - startTime;

        this.logger.errorWithException(
          `Request failed: ${method} ${url}`,
          error,
          undefined,
          {
            ...metadata,
            duration,
            statusCode: error.status || 500,
          },
        );

        return throwError(() => error);
      }),
    );
  }
}

import {
  CallHandler,
  ExecutionContext,
  Injectable,
  NestInterceptor,
} from '@nestjs/common';
import { Observable } from 'rxjs';
import { map } from 'rxjs/operators';
import {
  BaseResponse,
  ResponseMeta,
} from '@/common/interfaces/base-response.interface';

@Injectable()
export class ResponseInterceptor<T = unknown> implements NestInterceptor<
  T,
  BaseResponse<T>
> {
  intercept(
    context: ExecutionContext,
    next: CallHandler,
  ): Observable<BaseResponse<T>> {
    const ctx = context.switchToHttp();
    const response = ctx.getResponse();
    const request = ctx.getRequest();

    return next.handle().pipe(
      map((data) => {
        // If the response already has the expected format, return as-is
        if (data && typeof data === 'object' && 'success' in data) {
          return data;
        }

        // Otherwise, wrap it in the standard response format
        return {
          success: true,
          data,
          message: this.extractMessage(data),
          meta: {
            timestamp: new Date().toISOString(),
            requestId: request['requestId'],
            traceId: request['traceId'],
            pagination: this.extractPagination(data),
          },
        };
      }),
    );
  }

  private extractMessage(data: unknown): string | undefined {
    // Extract message from common response patterns
    if (data && typeof data === 'object') {
      const obj = data as Record<string, unknown>;
      if (obj.message) return String(obj.message);
      if (obj.msg) return String(obj.msg);
    }
    if (typeof data === 'string') return data;
    return undefined;
  }

  private extractPagination(data: unknown): ResponseMeta['pagination'] {
    // Extract pagination info if it exists
    if (data && typeof data === 'object') {
      const obj = data as Record<string, unknown>;
      if (obj.pagination) return obj.pagination as ResponseMeta['pagination'];
      if (
        obj.meta &&
        typeof obj.meta === 'object' &&
        'pagination' in obj.meta
      ) {
        return (obj.meta as Record<string, unknown>)
          .pagination as ResponseMeta['pagination'];
      }
      if (obj.page !== undefined || obj.limit !== undefined) {
        return {
          page: Number(obj.page),
          limit: Number(obj.limit),
          total: Number(obj.total),
          totalPages: Number(obj.totalPages),
        };
      }
    }
    return undefined;
  }
}

import { ErrorMetadata } from '@/common/errors/error.types';

export interface ErrorResponse {
  success: false;
  error: {
    code: string;
    type: string;
    message: string;
    details?: Array<{
      field?: string;
      message?: string;
      value?: any;
    }>;
  };
  meta: {
    timestamp: string;
    requestId?: string;
    traceId?: string;
    path?: string;
    method?: string;
    statusCode: number;
  };
}

export interface ValidationErrorResponse extends ErrorResponse {
  error: {
    code: 'VALIDATION_FAILED';
    type: 'VALIDATION';
    message: string;
    details: Array<{
      field: string;
      message: string;
      value?: any;
    }>;
  };
}

export interface SuccessResponse<T = any> {
  success: true;
  data: T;
  message: string;
  meta: {
    timestamp: string;
    requestId?: string;
    traceId?: string;
    pagination?: {
      page: number;
      limit: number;
      total: number;
      totalPages: number;
    };
  };
}

export function createErrorResponse(error: ErrorMetadata): ErrorResponse {
  return {
    success: false,
    error: {
      code: error.errorCode,
      type: error.errorType,
      message: error.message || 'An error occurred',
      details: error.details,
    },
    meta: {
      timestamp: error.timestamp,
      requestId: error.requestId,
      traceId: error.traceId,
      path: error.path,
      method: error.method,
      statusCode: error.statusCode,
    },
  };
}

export function createValidationErrorResponse(
  error: ErrorMetadata,
  details: Array<{ field: string; message: string; value?: any }>,
): ValidationErrorResponse {
  return {
    success: false,
    error: {
      code: 'VALIDATION_FAILED',
      type: 'VALIDATION',
      message: error.message || 'Validation failed',
      details,
    },
    meta: {
      timestamp: error.timestamp,
      requestId: error.requestId,
      traceId: error.traceId,
      path: error.path,
      method: error.method,
      statusCode: error.statusCode,
    },
  };
}

import {
  Injectable,
  NestMiddleware,
  LoggerService as NestLoggerService,
} from '@nestjs/common';
import { Request, Response, NextFunction } from 'express';
import { ConfigService } from '@nestjs/config';
import { JwtService } from '@nestjs/jwt';
import { AppLoggerService } from '@/common/services/logger.service';

export interface AuthenticatedRequest extends Request {
  user?: {
    id: string;
    email: string;
    role: string;
    sessionId?: string;
    lastLoginAt?: Date;
  };
  sessionId?: string;
  requestId?: string;
  traceId?: string;
}

@Injectable()
export class AuthMiddleware implements NestMiddleware {
  private readonly logger: AppLoggerService;
  private readonly jwtService: JwtService;
  private readonly excludedPaths: string[];

  constructor(
    private readonly configService: ConfigService,
    logger: NestLoggerService,
    jwtService: JwtService,
  ) {
    this.logger = logger as AppLoggerService;
    this.jwtService = jwtService;

    // Paths that don't require authentication
    this.excludedPaths = [
      '/health',
      '/metrics',
      '/auth/login',
      '/auth/register',
      '/auth/refresh',
      '/docs',
      '/swagger',
    ];
  }

  async use(
    req: AuthenticatedRequest,
    res: Response,
    next: NextFunction,
  ): Promise<void> {
    const startTime = Date.now();

    try {
      // Add correlation IDs
      this.addCorrelationIds(req);

      // Skip authentication for excluded paths
      if (this.isExcludedPath(req.path)) {
        this.logger.http(
          `Skipping authentication for excluded path: ${req.path}`,
          {
            requestId: req.requestId,
            traceId: req.traceId,
            path: req.path,
            method: req.method,
          },
        );

        req.user = undefined;
        return next();
      }

      // Extract token from headers
      const token = this.extractToken(req);

      if (!token) {
        this.logger.security('No authentication token provided', {
          requestId: req.requestId,
          traceId: req.traceId,
          path: req.path,
          method: req.method,
          ip: req.ip,
          userAgent: req.headers['user-agent'],
        });

        req.user = undefined;
        return next();
      }

      // Validate token
      const payload = await this.validateToken(token);

      if (!payload) {
        this.logger.security('Invalid authentication token', {
          requestId: req.requestId,
          traceId: req.traceId,
          path: req.path,
          method: req.method,
          ip: req.ip,
          userAgent: req.headers['user-agent'],
          token: token.substring(0, 20) + '...', // Don't log full token
        });

        req.user = undefined;
        return next();
      }

      // Check if user is active
      if (!payload.isActive) {
        this.logger.security('Inactive user attempted access', {
          requestId: req.requestId,
          traceId: req.traceId,
          path: req.path,
          method: req.method,
          ip: req.ip,
          userId: payload.id,
          email: payload.email,
        });

        req.user = undefined;
        return next();
      }

      // Attach user to request
      req.user = {
        id: payload.id,
        email: payload.email,
        role: payload.role,
        sessionId: payload.sessionId,
        lastLoginAt: payload.lastLoginAt,
      };

      // Log successful authentication
      const duration = Date.now() - startTime;
      this.logger.auth(`User authenticated successfully`, {
        requestId: req.requestId,
        traceId: req.traceId,
        userId: payload.id,
        email: payload.email,
        role: payload.role,
        duration,
        path: req.path,
        method: req.method,
        ip: req.ip,
      });

      // Add security headers
      this.addSecurityHeaders(res);

      next();
    } catch (error) {
      const duration = Date.now() - startTime;

      this.logger.errorWithException(
        'Authentication middleware error',
        error as Error,
        undefined,
        {
          requestId: req.requestId,
          traceId: req.traceId,
          path: req.path,
          method: req.method,
          duration,
          ip: req.ip,
        },
      );

      req.user = undefined;
      next();
    }
  }

  private addCorrelationIds(req: AuthenticatedRequest): void {
    // Extract or generate request ID
    req.requestId =
      (req.headers['x-request-id'] as string) ||
      `req_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

    // Extract or generate trace ID
    req.traceId =
      (req.headers['x-trace-id'] as string) ||
      `trace_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  }

  private isExcludedPath(path: string): boolean {
    return this.excludedPaths.some(
      (excludedPath) => path.startsWith(excludedPath) || path === excludedPath,
    );
  }

  private extractToken(req: Request): string | null {
    // Try Authorization header first
    const authHeader = req.headers.authorization;
    if (authHeader && authHeader.startsWith('Bearer ')) {
      return authHeader.substring(7);
    }

    // Try cookie
    const cookies = req.headers.cookie;
    if (cookies && typeof cookies === 'string') {
      const tokenMatch = cookies.match(/auth-token=([^;]+)/);
      if (tokenMatch) {
        return tokenMatch[1];
      }
    }

    // Try query parameter (for development/testing)
    const tokenQuery = req.query.token as string;
    if (tokenQuery) {
      return tokenQuery;
    }

    return null;
  }

  private async validateToken(token: string): Promise<any> {
    try {
      const payload = await this.jwtService.verifyAsync(token, {
        secret: this.configService.get('auth.jwt.accessToken.secret'),
        algorithms: ['HS256'],
        clockTolerance: 30, // Allow 30 seconds clock skew
      });

      return payload;
    } catch (error) {
      this.logger.security('Token validation failed', {
        error: error.message,
        token: token.substring(0, 20) + '...', // Don't log full token
      });

      return null;
    }
  }

  private addSecurityHeaders(res: Response): void {
    // Add security headers
    res.setHeader('X-Content-Type-Options', 'nosniff');
    res.setHeader('X-Frame-Options', 'DENY');
    res.setHeader('X-XSS-Protection', '1; mode=block');
    res.setHeader(
      'Strict-Transport-Security',
      'max-age=31536000; includeSubDomains',
    );
    res.setHeader('Referrer-Policy', 'strict-origin-when-cross-origin');

    // Add CORS headers if needed
    const corsOrigin = this.configService.get('app.corsOrigin');
    if (corsOrigin && corsOrigin !== '*') {
      res.setHeader('Access-Control-Allow-Origin', corsOrigin);
      res.setHeader('Vary', 'Origin');
    }
  }
}

import { PrismaService } from '@/modules/prisma/prisma.service';
import { AppLoggerService, LogContext } from '@/common/services/logger.service';
import { AppError } from '@/common/errors/app.error';

export interface PaginationOptions {
  page?: number;
  limit?: number;
  sortBy?: string;
  sortOrder?: 'asc' | 'desc';
}

export interface PaginationResult<T> {
  data: T[];
  pagination: {
    page: number;
    limit: number;
    total: number;
    totalPages: number;
    hasNext: boolean;
    hasPrev: boolean;
  };
}

export interface QueryOptions {
  include?: any;
  select?: any;
  where?: any;
  orderBy?: any;
}

export abstract class BaseRepository<T> {
  constructor(
    protected readonly prisma: PrismaService,
    protected readonly logger: AppLoggerService,
    protected readonly modelName: string,
  ) {}

  protected async executeWithLogging<R>(
    operation: string,
    callback: () => Promise<R>,
    metadata?: Record<string, any>,
  ): Promise<R> {
    const timer = this.logger.startTimer(
      `${this.modelName}.${operation}`,
      metadata,
    );

    try {
      const result = await callback();
      timer();

      this.logger.database(
        `${this.modelName} ${operation} completed successfully`,
        {
          ...metadata,
          operation: `${this.modelName}.${operation}`,
          success: true,
        },
      );

      return result;
    } catch (error) {
      timer();

      this.logger.errorWithException(
        `${this.modelName} ${operation} failed`,
        error as Error,
        LogContext.DATABASE,
        {
          ...metadata,
          operation: `${this.modelName}.${operation}`,
          success: false,
        },
      );

      if (error instanceof AppError) {
        throw error;
      }

      // Convert database errors to AppError
      throw AppError.databaseError(
        `Database ${operation} failed for ${this.modelName}`,
        error as Error,
        {
          modelName: this.modelName,
          operation,
        },
      );
    }
  }

  protected async findById(
    id: string,
    options?: QueryOptions,
  ): Promise<T | null> {
    return this.executeWithLogging(
      'findById',
      async () => {
        const model = this.getModel();
        const result = await model.findUnique({
          where: { id },
          ...options,
        });

        return result as T | null;
      },
      { id },
    );
  }

  protected async findOne(
    where: any,
    options?: QueryOptions,
  ): Promise<T | null> {
    return this.executeWithLogging(
      'findOne',
      async () => {
        const model = this.getModel();
        const result = await model.findFirst({
          where,
          ...options,
        });

        return result as T | null;
      },
      { where },
    );
  }

  protected async findMany(where?: any, options?: QueryOptions): Promise<T[]> {
    return this.executeWithLogging(
      'findMany',
      async () => {
        const model = this.getModel();
        const result = await model.findMany({
          where,
          ...options,
        });

        return result as T[];
      },
      { where },
    );
  }

  protected async findManyWithPagination(
    where?: any,
    pagination?: PaginationOptions,
    options?: QueryOptions,
  ): Promise<PaginationResult<T>> {
    return this.executeWithLogging(
      'findManyWithPagination',
      async () => {
        const model = this.getModel();
        const page = pagination?.page || 1;
        const limit = pagination?.limit || 10;
        const skip = (page - 1) * limit;

        // Get total count
        const total = await model.count({ where });

        // Get data
        const orderBy = pagination?.sortBy
          ? { [pagination.sortBy]: pagination.sortOrder || 'asc' }
          : options?.orderBy || {};

        const data = await model.findMany({
          where,
          skip,
          take: limit,
          orderBy,
          ...options,
        });

        const totalPages = Math.ceil(total / limit);

        return {
          data: data as T[],
          pagination: {
            page,
            limit,
            total,
            totalPages,
            hasNext: page < totalPages,
            hasPrev: page > 1,
          },
        };
      },
      { where, pagination },
    );
  }

  protected async create(data: Partial<T>, options?: QueryOptions): Promise<T> {
    return this.executeWithLogging(
      'create',
      async () => {
        const model = this.getModel();
        const result = await model.create({
          data,
          ...options,
        });

        return result as T;
      },
      { data },
    );
  }

  protected async createMany(data: Partial<T>[]): Promise<{ count: number }> {
    return this.executeWithLogging(
      'createMany',
      async () => {
        const model = this.getModel();
        const result = await model.createMany({
          data,
        });

        return result;
      },
      { count: data.length },
    );
  }

  protected async update(
    id: string,
    data: Partial<T>,
    options?: QueryOptions,
  ): Promise<T> {
    return this.executeWithLogging(
      'update',
      async () => {
        const model = this.getModel();
        const result = await model.update({
          where: { id },
          data,
          ...options,
        });

        return result as T;
      },
      { id, data },
    );
  }

  protected async updateMany(
    where: any,
    data: Partial<T>,
  ): Promise<{ count: number }> {
    return this.executeWithLogging(
      'updateMany',
      async () => {
        const model = this.getModel();
        const result = await model.updateMany({
          where,
          data,
        });

        return result;
      },
      { where, data },
    );
  }

  protected async delete(id: string, options?: QueryOptions): Promise<T> {
    return this.executeWithLogging(
      'delete',
      async () => {
        const model = this.getModel();
        const result = await model.delete({
          where: { id },
          ...options,
        });

        return result as T;
      },
      { id },
    );
  }

  protected async deleteMany(where: any): Promise<{ count: number }> {
    return this.executeWithLogging(
      'deleteMany',
      async () => {
        const model = this.getModel();
        const result = await model.deleteMany({
          where,
        });

        return result;
      },
      { where },
    );
  }

  protected async count(where?: any): Promise<number> {
    return this.executeWithLogging(
      'count',
      async () => {
        const model = this.getModel();
        const result = await model.count({ where });

        return result;
      },
      { where },
    );
  }

  protected async exists(where: any): Promise<boolean> {
    return this.executeWithLogging(
      'exists',
      async () => {
        const model = this.getModel();
        const result = await model.count({ where });

        return result > 0;
      },
      { where },
    );
  }

  // Transaction support
  protected async runInTransaction<R>(
    callback: (tx: any) => Promise<R>,
    metadata?: Record<string, any>,
  ): Promise<R> {
    return this.executeWithLogging(
      'transaction',
      async () => {
        return await this.prisma.$transaction(callback);
      },
      metadata,
    );
  }

  // Health check
  protected async healthCheck(): Promise<{
    connected: boolean;
    responseTime: number;
    error?: string;
  }> {
    const startTime = Date.now();

    try {
      await this.prisma.$queryRaw`SELECT 1`;
      const responseTime = Date.now() - startTime;

      return {
        connected: true,
        responseTime,
      };
    } catch (error) {
      const responseTime = Date.now() - startTime;

      return {
        connected: false,
        responseTime,
        error: (error as Error).message,
      };
    }
  }

  // Abstract method to get the specific model
  protected abstract getModel(): any;
}

