import { Processor, WorkerHost } from '@nestjs/bullmq';
import { Job } from 'bullmq';
import { Logger } from '@nestjs/common';
import { EmailService } from '../application/services/email.service';
import { InjectMetric } from '@willsoto/nestjs-prometheus';
import { Histogram } from 'prom-client';
import {
  NOTIFICATION_QUEUE,
  NOTIFICATION_JOBS,
} from '../notification.constants';

interface SendWelcomeEmailJob {
  userId: string;
  email: string;
  firstName: string;
}

interface SendAccountUpdateEmailJob {
  userId: string;
  email: string;
  firstName: string;
  changes: any;
}

@Processor(NOTIFICATION_QUEUE)
export class EmailProcessor extends WorkerHost {
  private readonly logger = new Logger(EmailProcessor.name);

  constructor(
    private readonly emailService: EmailService,
    @InjectMetric('queue_job_duration_seconds')
    private readonly jobDuration: Histogram<string>,
  ) {
    super();
  }

  async process(job: Job<any, any, string>): Promise<any> {
    const startTime = Date.now();
    this.logger.log(`[Queue] Processing job: ${job.id} type: ${job.name}`);

    try {
      let result;
      switch (job.name) {
        case NOTIFICATION_JOBS.SEND_WELCOME_EMAIL:
          const welcomeData = job.data as SendWelcomeEmailJob;
          result = await this.emailService.sendWelcomeEmail(
            welcomeData.email,
            welcomeData.firstName,
          );
          break;
        case 'send-account-update-email':
          const updateData = job.data as SendAccountUpdateEmailJob;
          result = await this.emailService.sendAccountUpdateEmail(
            updateData.email,
            updateData.firstName,
            updateData.changes,
          );
          break;
        default:
          this.logger.warn(`[Queue] Unknown job type: ${job.name}`);
      }

      const duration = (Date.now() - startTime) / 1000;
      this.jobDuration.observe(
        { queue: NOTIFICATION_QUEUE, job: job.name },
        duration,
      );
      return result;
    } catch (error) {
      const duration = (Date.now() - startTime) / 1000;
      this.jobDuration.observe(
        { queue: NOTIFICATION_QUEUE, job: job.name },
        duration,
      );
      this.logger.error(
        `[Queue] Job ${job.id} failed: ${error.message}`,
        error.stack,
      );
      throw error;
    }
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { OnEvent } from '@nestjs/event-emitter';
import { InjectQueue } from '@nestjs/bullmq';
import { Queue } from 'bullmq';
import {
  NOTIFICATION_QUEUE,
  NOTIFICATION_JOBS,
} from '../notification.constants';
import {
  UserCreatedEvent,
  UserUpdatedEvent,
} from '../../user/domain/events/user-events';

interface SendWelcomeEmailJob {
  userId: string;
  email: string;
  firstName: string;
}

interface SendAccountUpdateEmailJob {
  userId: string;
  email: string;
  firstName: string;
  changes: any;
}

@Injectable()
export class NotificationListener {
  private readonly logger = new Logger(NotificationListener.name);

  constructor(
    @InjectQueue(NOTIFICATION_QUEUE) private readonly notificationQueue: Queue,
  ) {}

  @OnEvent('user.created')
  async handleUserCreated(event: UserCreatedEvent) {
    this.logger.log(
      `[Notification] Enqueuing welcome email for ${event.email}`,
    );

    const jobData: SendWelcomeEmailJob = {
      userId: event.userId,
      email: event.email,
      firstName: event.firstName,
    };

    await this.notificationQueue.add(
      NOTIFICATION_JOBS.SEND_WELCOME_EMAIL,
      jobData,
      {
        attempts: 3,
        backoff: { type: 'exponential', delay: 2000 },
        removeOnComplete: 100,
        removeOnFail: 50,
      },
    );
  }

  @OnEvent('user.updated')
  async handleUserUpdated(event: UserUpdatedEvent) {
    this.logger.log(
      `[Notification] Enqueuing account update alert for ${event.email}`,
    );

    const jobData: SendAccountUpdateEmailJob = {
      userId: event.userId,
      email: event.email,
      firstName: event.firstName,
      changes: event.changes,
    };

    await this.notificationQueue.add('send-account-update-email', jobData, {
      attempts: 2,
      backoff: { type: 'exponential', delay: 5000 },
      removeOnComplete: 100,
      removeOnFail: 50,
    });
  }
}

export interface SendWelcomeEmailJob {
  userId: string;
  email: string;
  firstName: string;
}

export interface SendAccountUpdateEmailJob {
  userId: string;
  email: string;
  firstName: string;
  changes: any;
}

import { BaseEntity } from '@/common/domain/base.entity';

export class ProductEntity extends BaseEntity {
  private _name: string;
  private _description: string;
  private _price: number;
  private _stock: number;
  private _isActive: boolean;

  private constructor(data: ProductSnapshot) {
    super(data.id, data.createdAt, data.updatedAt);
    this._name = data.name;
    this._description = data.description;
    this._price = data.price;
    this._stock = data.stock;
    this._isActive = data.isActive ?? true;
  }

  static create(
    name: string,
    description: string,
    price: number,
    stock: number,
  ): ProductEntity {
    if (price <= 0) {
      throw new Error('Price must be greater than 0');
    }
    if (stock < 0) {
      throw new Error('Stock cannot be negative');
    }

    const now = new Date();
    const { v4: uuidv4 } = require('uuid');

    return new ProductEntity({
      id: uuidv4(),
      name: name.trim(),
      description: description.trim(),
      price,
      stock,
      isActive: true,
      createdAt: now,
      updatedAt: now,
    });
  }

  static reconstitute(data: ProductSnapshot): ProductEntity {
    return new ProductEntity(data);
  }

  // Getters
  get name(): string {
    return this._name;
  }
  get description(): string {
    return this._description;
  }
  get price(): number {
    return this._price;
  }
  get stock(): number {
    return this._stock;
  }
  get isActive(): boolean {
    return this._isActive;
  }

  // Business methods
  updatePrice(newPrice: number): void {
    if (newPrice <= 0) {
      throw new Error('Price must be greater than 0');
    }
    this._price = newPrice;
    this.touch();
  }

  adjustStock(quantity: number): void {
    const newStock = this._stock + quantity;
    if (newStock < 0) {
      throw new Error('Insufficient stock');
    }
    this._stock = newStock;
    this.touch();
  }

  activate(): void {
    this._isActive = true;
    this.touch();
  }

  deactivate(): void {
    this._isActive = false;
    this.touch();
  }

  toSnapshot(): ProductSnapshot {
    return {
      id: this._id,
      name: this._name,
      description: this._description,
      price: this._price,
      stock: this._stock,
      isActive: this._isActive,
      createdAt: this._createdAt,
      updatedAt: this._updatedAt,
    };
  }
}

export interface ProductSnapshot {
  id: string;
  name: string;
  description: string;
  price: number;
  stock: number;
  isActive: boolean;
  createdAt: Date;
  updatedAt: Date;
}

import { Injectable } from '@nestjs/common';
import { ProductEntity } from '../../domain/entities/product.entity';
import {
  IProductRepository,
  PaginationOptions,
  PaginatedResult,
  CreateProductDto,
  UpdateProductDto,
} from '../../domain/repositories/product.repository.interface';
import { PrismaService } from '@/modules/prisma/prisma.service';
import { BaseRepository } from '@/common/repositories/base.repository';
import { AppLoggerService } from '@/common/services/logger.service';

@Injectable()
export class PrismaProductRepository
  extends BaseRepository<ProductEntity>
  implements IProductRepository
{
  constructor(prisma: PrismaService, logger: AppLoggerService) {
    super(prisma, logger, 'Product');
  }

  protected getModel() {
    return this.prisma.product;
  }

  private mapToDomain(product: any): ProductEntity {
    return ProductEntity.reconstitute({
      id: product.id,
      name: product.name,
      description: product.description,
      price: product.price,
      stock: product.stock,
      isActive: product.isActive,
      createdAt: product.createdAt,
      updatedAt: product.updatedAt,
    });
  }

  async findById(id: string): Promise<ProductEntity | null> {
    const product = await super.findById(id);
    return product ? this.mapToDomain(product) : null;
  }

  async findAll(
    options: PaginationOptions,
  ): Promise<PaginatedResult<ProductEntity>> {
    const { page, limit, sortBy = 'createdAt', sortOrder = 'desc' } = options;

    const result = await super.findManyWithPagination(undefined, {
      page,
      limit,
      sortBy,
      sortOrder,
    });

    return {
      data: result.data.map((product) => this.mapToDomain(product)),
      pagination: result.pagination,
    };
  }

  async create(data: CreateProductDto): Promise<ProductEntity> {
    const product = await super.create(data);
    return this.mapToDomain(product);
  }

  async update(id: string, data: UpdateProductDto): Promise<ProductEntity> {
    const product = await super.update(id, data);
    return this.mapToDomain(product);
  }

  async delete(id: string): Promise<void> {
    await super.delete(id);
  }

  async count(where?: any): Promise<number> {
    return await super.count(where);
  }

  async exists(where: any): Promise<boolean> {
    return await super.exists(where);
  }

  async existsByName(name: string): Promise<boolean> {
    return await super.exists({ name });
  }
}

