describe('CreateUserUseCase', () => {
  let useCase: CreateUserUseCase;
  let repo: any;
  let eventEmitter: any;

  beforeEach(async () => {
    repo = createMockRepository({
      findByEmail: jest.fn(),
      existsByEmail: jest.fn(),
      create: jest.fn(),
    });

    eventEmitter = {
      emit: jest.fn(),
    };

    const module = await createTestModule({
      providers: [
        CreateUserUseCase,
        { provide: USER_REPOSITORY, useValue: repo },
        { provide: EventEmitter2, useValue: eventEmitter },
      ],
    });

    useCase = module.get<CreateUserUseCase>(CreateUserUseCase);
  });

  it('should create a user successfully and emit UserCreatedEvent', async () => {
    // Arrange
    const dto: CreateUserDataDto = {
      email: 'test@example.com',
      password: 'password123',
      firstName: 'John',
      lastName: 'Doe',
      role: Role.USER,
    };
    repo.existsByEmail.mockResolvedValue(false);
    repo.create.mockResolvedValue({
      id: '1',
      email: dto.email,
      firstName: dto.firstName,
      lastName: dto.lastName,
      createdAt: new Date(),
    });

    // Act
    const result = await useCase.execute(dto);

    // Assert
    expect(result).toBeDefined();
    expect(result.email).toBe(dto.email);
    expect(repo.create).toHaveBeenCalled();
    expect(eventEmitter.emit).toHaveBeenCalledWith(
      'user.created',
      expect.objectContaining({
        email: dto.email,
        firstName: 'John',
      }),
    );
  });

  it('should throw ConflictException if email already exists', async () => {
    // Arrange
    const dto: CreateUserDataDto = {
      email: 'test@example.com',
      password: 'password123',
      firstName: 'John',
      lastName: 'Doe',
      role: Role.USER,
    };
    repo.existsByEmail.mockResolvedValue(true);

    // Act & Assert
    await expect(useCase.execute(dto)).rejects.toThrow(ConflictError);
    expect(repo.create).not.toHaveBeenCalled();
    expect(eventEmitter.emit).not.toHaveBeenCalled();
  });
});

import { Inject, Injectable, Logger } from '@nestjs/common';
import { EventEmitter2 } from '@nestjs/event-emitter';
import {
  IUserRepository,
  CreateUserDataDto,
} from '../../domain/repositories/user.repository.interface';
import { INJECTION_TOKENS } from '@/constants/injection-tokens';
import { UserEntity } from '../../domain/entities/user.entity';
import { ConflictError } from '@/common/domain/errors/application.error';
import { v4 as uuidv4 } from 'uuid';
import * as argon2 from 'argon2';

@Injectable()
export class CreateUserUseCase {
  private readonly logger = new Logger(CreateUserUseCase.name);

  constructor(
    @Inject(INJECTION_TOKENS.USER_REPOSITORY)
    private readonly userRepo: IUserRepository,
    private readonly eventEmitter: EventEmitter2,
  ) {}

  async execute(dto: CreateUserDataDto): Promise<UserEntity> {
    const exists = await this.userRepo.existsByEmail(dto.email);
    if (exists) {
      throw new ConflictError(`User with email ${dto.email} already exists`);
    }

    const passwordHash = await argon2.hash(dto.password);

    const user = await this.userRepo.create({
      email: dto.email,
      firstName: dto.firstName,
      lastName: dto.lastName,
      passwordHash,
      role: dto.role,
    });

    // Emit event — listener sẽ push vào queue async
    this.eventEmitter.emit('user.created', {
      userId: user.id,
      email: user.email,
      firstName: user.firstName,
      createdAt: user.createdAt,
    });

    return user;
  }
}

import { Inject, Injectable, NotFoundException, Logger } from '@nestjs/common';
import { CACHE_MANAGER } from '@nestjs/cache-manager';
import { Cache } from 'cache-manager';
import { EventEmitter2 } from '@nestjs/event-emitter';
import { IUserRepository } from '../../domain/repositories/user.repository.interface';
import { INJECTION_TOKENS } from '@/constants/injection-tokens';
import { CacheKeys } from '@/constants/cache.constant';
import type { ITokenStore } from '@/modules/auth/infrastructure/token-store/redis-token-store';

@Injectable()
export class DeleteUserUseCase {
  private readonly logger = new Logger(DeleteUserUseCase.name);

  constructor(
    @Inject(INJECTION_TOKENS.USER_REPOSITORY)
    private readonly userRepo: IUserRepository,
    @Inject(CACHE_MANAGER) private readonly cache: Cache,
    // Add: inject token store
    @Inject(INJECTION_TOKENS.TOKEN_STORE)
    private readonly tokenStore: ITokenStore,
    private readonly eventEmitter: EventEmitter2,
  ) {}

  async execute(id: string): Promise<void> {
    const user = await this.userRepo.findById(id);
    if (!user) {
      throw new NotFoundException(`User with ID ${id} not found`);
    }

    // Soft delete
    await this.userRepo.delete(id);

    // Add: Revoke all sessions of user in Redis
    try {
      await this.tokenStore.revokeAll(id);
      this.logger.log(`[DeleteUser] Revoked all sessions: userId=${id}`);
    } catch (err) {
      // Log warning but don't block - user already soft deleted
      this.logger.error(
        `[DeleteUser] Failed to revoke sessions: userId=${id}`,
        err,
      );
    }

    // Invalidate cache
    try {
      await Promise.all([
        this.cache.del(CacheKeys.user(id)),
        this.cache.del(CacheKeys.userByEmail(user.email)),
        this.cache.del(CacheKeys.userList(1, 20)),
      ]);
    } catch (err) {
      this.logger.warn('Cache invalidation failed', { id, err });
    }

    this.eventEmitter.emit('user.deleted', {
      userId: user.id,
      email: user.email,
    });
  }
}

